import{_ as e,o as a,c as o,a2 as d}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Brainstorm D: Repo-to-Workflow Map","description":"","frontmatter":{},"headers":[],"relativePath":"brainstorm/d-repo-map.md","filePath":"brainstorm/d-repo-map.md"}'),r={name:"brainstorm/d-repo-map.md"};function i(s,t,n,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="brainstorm-d-repo-to-workflow-map" tabindex="-1">Brainstorm D: Repo-to-Workflow Map <a class="header-anchor" href="#brainstorm-d-repo-to-workflow-map" aria-label="Permalink to &quot;Brainstorm D: Repo-to-Workflow Map&quot;">​</a></h1><p><strong>Date:</strong> 2026-07-06<br><strong>Owner:</strong> Paijo (BerkahKarya)<br><strong>Status:</strong> Ground Truth Mapping</p><hr><h2 id="executive-summary" tabindex="-1">Executive Summary <a class="header-anchor" href="#executive-summary" aria-label="Permalink to &quot;Executive Summary&quot;">​</a></h2><p>The doc claimed Section 4 was &quot;incomplete.&quot; This map closes that gap using the actual repos on disk.</p><hr><h2 id="_1-full-workflow-→-repo-map" tabindex="-1">1. Full Workflow → Repo Map <a class="header-anchor" href="#_1-full-workflow-→-repo-map" aria-label="Permalink to &quot;1. Full Workflow → Repo Map&quot;">​</a></h2><h3 id="wf1-content-engine" tabindex="-1">WF1: Content Engine <a class="header-anchor" href="#wf1-content-engine" aria-label="Permalink to &quot;WF1: Content Engine&quot;">​</a></h3><p><strong>Goal:</strong> Build audience trust, generate leads, soft-sell products</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>1ai-content</code></td><td>Exists</td><td>Content generation, scheduling</td><td>Unknown depth — needs audit</td></tr><tr><td><code>1ai-berkahkarya-website</code></td><td>Exists + deployed</td><td>Marketing site, landing pages</td><td>No blog/SEO content pipeline</td></tr><tr><td><code>1ai-social</code></td><td>Exists</td><td>Social media posting via PostBridge</td><td>Posting works; analytics thin</td></tr><tr><td><code>1ai-skills/</code></td><td>Exists</td><td>Agent skills for content tasks</td><td>Fragmented — no unified WF1 orchestration</td></tr></tbody></table><p><strong>Owner repo:</strong> <code>1ai-content</code><br><strong>Gap:</strong> No single orchestration script that goes &quot;topic → draft → schedule → post → report.&quot; Each step is isolated.</p><hr><h3 id="wf2-outreach-community" tabindex="-1">WF2: Outreach &amp; Community <a class="header-anchor" href="#wf2-outreach-community" aria-label="Permalink to &quot;WF2: Outreach &amp; Community&quot;">​</a></h3><p><strong>Goal:</strong> Direct human connections, partnerships, trust-building at scale</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>1ai-social</code></td><td>Exists</td><td>Marketplace inbox, social engagement</td><td>Outreach not systematized</td></tr><tr><td><code>.hermes/hermes-agent</code></td><td>Exists</td><td>Orchestration layer</td><td>Hermes doesn&#39;t have a WF2 skill</td></tr><tr><td><code>1ai-career</code></td><td>Exists</td><td>Job/collaboration leads</td><td>Unclear if this feeds WF2</td></tr></tbody></table><p><strong>Owner repo:</strong> None (orphaned workflow)<br><strong>Gap:</strong> WF2 has no primary repo. Needs either a new <code>1ai-outreach</code> repo OR a dedicated module in <code>1ai-social</code>.</p><hr><h3 id="wf3-skills-knowledge-products" tabindex="-1">WF3: Skills &amp; Knowledge Products <a class="header-anchor" href="#wf3-skills-knowledge-products" aria-label="Permalink to &quot;WF3: Skills &amp; Knowledge Products&quot;">​</a></h3><p><strong>Goal:</strong> Package expertise into sellable digital products (ebooks, courses, templates)</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>1ai-berkahkarya-website</code></td><td>Exists</td><td>Landing pages for products</td><td>Products not yet built</td></tr><tr><td><code>1ai-payment</code></td><td>Exists</td><td>Payment processing (Tripay)</td><td>Works but no product catalog</td></tr><tr><td><code>1ai-harvest</code></td><td>Exists</td><td>?</td><td>Need to audit</td></tr><tr><td><code>1ai-playbook</code></td><td>Exists</td><td>Internal playbooks</td><td>These are private, not products</td></tr></tbody></table><p><strong>Owner repo:</strong> <code>1ai-berkahkarya-website</code> (storefront) + <code>1ai-payment</code> (transactions)<br><strong>Gap:</strong> No product catalog system. No digital delivery (ebook download, course access). No subscription management beyond Tripay.</p><hr><h3 id="wf4-product-saas-sales" tabindex="-1">WF4: Product &amp; SaaS Sales <a class="header-anchor" href="#wf4-product-saas-sales" aria-label="Permalink to &quot;WF4: Product &amp; SaaS Sales&quot;">​</a></h3><p><strong>Goal:</strong> Sell trading tools, AI products, SaaS subscriptions</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>1ai-trade-cex</code></td><td>Exists, 975 tests</td><td>Core trading platform, 8 Telegram bots</td><td>Subscription billing not connected to Capital Pool</td></tr><tr><td><code>1ai-trade-bot</code></td><td>Exists</td><td>?</td><td>Need to audit vs. 1ai-trade-cex</td></tr><tr><td><code>1ai-trade-dex</code></td><td>Exists</td><td>DEX trading</td><td>Unknown maturity</td></tr><tr><td><code>OmniRoute</code></td><td>Exists</td><td>AI router product</td><td>Separate business line</td></tr><tr><td><code>1ai-tracker</code></td><td>Exists</td><td>Next.js tracker</td><td>Unknown purpose</td></tr><tr><td><code>1ai-affiliate</code></td><td>Exists, 3-layer stack</td><td>Affiliate tracking platform</td><td>Can sell as SaaS; not listed as WF4 product</td></tr></tbody></table><p><strong>Owner repo:</strong> <code>1ai-trade-cex</code><br><strong>Gap:</strong> Revenue from <code>1ai-trade-cex</code> subscriptions not automatically deposited to Capital Pool. <code>1ai-trade-bot</code> vs. <code>1ai-trade-cex</code> overlap unclear.</p><hr><h3 id="wf5-active-trading-capital-multiplier" tabindex="-1">WF5: Active Trading (Capital Multiplier) <a class="header-anchor" href="#wf5-active-trading-capital-multiplier" aria-label="Permalink to &quot;WF5: Active Trading (Capital Multiplier)&quot;">​</a></h3><p><strong>Goal:</strong> Multiply capital via algorithmic trading (Forex, Crypto, Indices)</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>1ai-trade-cex</code></td><td>Exists, production</td><td>8 bots: Forex, Crypto, Commodities, Binary, DEX, Indices</td><td>No Capital Pool integration</td></tr><tr><td><code>idx-trading-bot</code></td><td>Exists</td><td>Indonesian stock market bot</td><td>Separate, IDX-specific</td></tr><tr><td><code>1ai-trade-dex</code></td><td>Exists</td><td>DEX (on-chain) trading</td><td>Unknown maturity</td></tr><tr><td><code>venv-backtest</code></td><td>Exists</td><td>Backtesting environment</td><td>Local dev tool, not deployed</td></tr></tbody></table><p><strong>Owner repo:</strong> <code>1ai-trade-cex</code><br><strong>Gaps:</strong></p><ol><li>No Capital Pool integration (PnL not reported to pool)</li><li>No Hermes trigger integration (drawdown limits not enforced system-wide)</li><li><code>idx-trading-bot</code> vs. <code>1ai-trade-cex</code> - are they separate? Does IDX bot report to same pool?</li></ol><hr><h3 id="wf6-automation-middleman-arbitrage-engine" tabindex="-1">WF6: Automation Middleman (Arbitrage Engine) <a class="header-anchor" href="#wf6-automation-middleman-arbitrage-engine" aria-label="Permalink to &quot;WF6: Automation Middleman (Arbitrage Engine)&quot;">​</a></h3><p><strong>Goal:</strong> Buy-low-sell-high on C2C marketplaces — bootstrap capital without dependencies</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>1ai-social/ai_social/marketplace/</code></td><td>Exists, 32/32 tests</td><td>Full marketplace engine: scan, score, post, reply, treasury</td><td>Not deployed to production yet</td></tr><tr><td><code>waha-core</code></td><td>Exists</td><td>WhatsApp API (WAHA)</td><td>Can be used for buyer comms via WhatsApp</td></tr><tr><td><code>waha-dashboard</code></td><td>Exists</td><td>WAHA management UI</td><td>Supporting infra</td></tr></tbody></table><p><strong>Owner repo:</strong> <code>1ai-social</code> (marketplace module)<br><strong>Gaps:</strong></p><ol><li>Not deployed to production — needs PM2/Cron setup</li><li>Treasury (<code>TreasuryBridge</code>) not connected to Capital Pool</li><li>OLX/Facebook adapters work but accounts need to be registered + tested</li><li>No multi-account rotation yet (single account per platform)</li></ol><hr><h3 id="orchestration-layer-hermes-gm" tabindex="-1">Orchestration Layer: Hermes GM <a class="header-anchor" href="#orchestration-layer-hermes-gm" aria-label="Permalink to &quot;Orchestration Layer: Hermes GM&quot;">​</a></h3><p><strong>Goal:</strong> Cross-workflow orchestration, decision-making, Vilona&#39;s execution layer</p><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th><th>Gap</th></tr></thead><tbody><tr><td><code>.hermes/hermes-agent</code></td><td>Exists</td><td>Core Hermes agent</td><td>No workflow trigger rules loaded</td></tr><tr><td><code>1ai-hub</code></td><td>Exists</td><td>Hub: brain, memory, routing</td><td>Capital Pool service not built</td></tr><tr><td><code>1ai-hub/hub-core</code></td><td>Exists</td><td>Shared client library</td><td><code>capital_pool.py</code> client missing</td></tr><tr><td><code>1ai-skills/</code></td><td>Exists</td><td>Agent skills</td><td>Hermes skills not mapped to workflows</td></tr></tbody></table><p><strong>Owner repo:</strong> <code>.hermes/hermes-agent</code> + <code>1ai-hub</code><br><strong>Gaps:</strong></p><ol><li>Hermes has no Capital Pool awareness</li><li>No trigger rules defined (brainstorm C addresses this)</li><li>Vilona ↔ Hermes communication not systematized</li></ol><hr><h3 id="infrastructure-cross-cutting" tabindex="-1">Infrastructure &amp; Cross-Cutting <a class="header-anchor" href="#infrastructure-cross-cutting" aria-label="Permalink to &quot;Infrastructure &amp; Cross-Cutting&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Repo</th><th>Status</th><th>Role</th></tr></thead><tbody><tr><td><code>1ai-hub</code></td><td>Core</td><td>Brain, memory, auth, routing hub</td></tr><tr><td><code>1ai-cf-router</code></td><td>Exists</td><td>Cloudflare routing layer</td></tr><tr><td><code>1ai-mt-router</code></td><td>Exists</td><td>MT (MetaTrader?) router</td></tr><tr><td><code>1ai-payment</code></td><td>Exists</td><td>Payment processing</td></tr><tr><td><code>1ai-osint</code></td><td>Exists</td><td>OSINT tooling</td></tr><tr><td><code>1ai-auto-bounty</code></td><td>Exists</td><td>Automated bug bounty</td></tr><tr><td><code>1ai-auto-hunt</code></td><td>Exists</td><td>Automated hunting</td></tr><tr><td><code>1ai-phonefarm</code></td><td>Exists</td><td>Phone farm management</td></tr></tbody></table><hr><h2 id="_2-workflow-coverage-matrix" tabindex="-1">2. Workflow Coverage Matrix <a class="header-anchor" href="#_2-workflow-coverage-matrix" aria-label="Permalink to &quot;2. Workflow Coverage Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>Primary Repo</th><th>Tests</th><th>Deployed?</th><th>Capital Pool Connected?</th><th>Score</th></tr></thead><tbody><tr><td>WF1 Content</td><td><code>1ai-content</code></td><td>?</td><td>Partial</td><td>❌</td><td>🟡 40%</td></tr><tr><td>WF2 Outreach</td><td>None</td><td>❌</td><td>❌</td><td>❌</td><td>🔴 10%</td></tr><tr><td>WF3 Products</td><td><code>1ai-berkahkarya-website</code></td><td>?</td><td>Yes (site)</td><td>❌</td><td>🟡 30%</td></tr><tr><td>WF4 SaaS Sales</td><td><code>1ai-trade-cex</code></td><td>975 ✅</td><td>Yes</td><td>❌</td><td>🟢 70%</td></tr><tr><td>WF5 Trading</td><td><code>1ai-trade-cex</code></td><td>975 ✅</td><td>Yes</td><td>❌</td><td>🟢 65%</td></tr><tr><td>WF6 Arbitrage</td><td><code>1ai-social/marketplace</code></td><td>32/32 ✅</td><td>❌</td><td>❌</td><td>🟡 55%</td></tr><tr><td>Hermes Orchestration</td><td><code>.hermes/hermes-agent</code></td><td>?</td><td>Partial</td><td>❌</td><td>🟡 40%</td></tr><tr><td>Capital Pool</td><td><code>1ai-hub</code></td><td>❌</td><td>❌</td><td>N/A</td><td>🔴 0%</td></tr></tbody></table><p><strong>Critical finding: Capital Pool = 0%. Everything else is blocked from being a real flywheel until this exists.</strong></p><hr><h2 id="_3-redundancy-overlap-issues" tabindex="-1">3. Redundancy / Overlap Issues <a class="header-anchor" href="#_3-redundancy-overlap-issues" aria-label="Permalink to &quot;3. Redundancy / Overlap Issues&quot;">​</a></h2><h3 id="issue-1-1ai-trade-bot-vs-1ai-trade-cex" tabindex="-1">Issue 1: <code>1ai-trade-bot</code> vs. <code>1ai-trade-cex</code> <a class="header-anchor" href="#issue-1-1ai-trade-bot-vs-1ai-trade-cex" aria-label="Permalink to &quot;Issue 1: `1ai-trade-bot` vs. `1ai-trade-cex`&quot;">​</a></h3><ul><li>Both exist, both seem to be trading bots</li><li><code>1ai-trade-cex</code> has 975 tests and multi-bot architecture</li><li><code>1ai-trade-bot</code> status unknown</li><li><strong>Decision needed:</strong> Are these parallel? Is <code>1ai-trade-bot</code> the older version?</li><li><strong>Recommendation:</strong> Audit, then consolidate or clearly separate</li></ul><h3 id="issue-2-1ai-social-vs-standalone-marketplace" tabindex="-1">Issue 2: <code>1ai-social</code> vs. standalone marketplace <a class="header-anchor" href="#issue-2-1ai-social-vs-standalone-marketplace" aria-label="Permalink to &quot;Issue 2: `1ai-social` vs. standalone marketplace&quot;">​</a></h3><ul><li><code>1ai-social</code> contains <code>marketplace/</code> module — good architecture</li><li>But the parent <code>1ai-social</code> also has other modules (content?, social media?)</li><li><strong>Risk:</strong> Marketplace gets buried in a larger codebase, harder to maintain</li><li><strong>Recommendation:</strong> Keep as module for now, consider split if complexity grows</li></ul><h3 id="issue-3-1ai-skills-scatter" tabindex="-1">Issue 3: <code>1ai-skills</code> scatter <a class="header-anchor" href="#issue-3-1ai-skills-scatter" aria-label="Permalink to &quot;Issue 3: `1ai-skills` scatter&quot;">​</a></h3><ul><li>Skills live in both <code>~/1ai-skills/</code> (root) and <code>~/projects/1ai-skills/</code> and <code>~/projects/1ai-ecosystem-skills/</code></li><li>Multiple copies of the same skill ecosystem</li><li><strong>Recommendation:</strong> Establish canonical location, symlink or consolidate</li></ul><h3 id="issue-4-1ai-hub-vs-gbrain" tabindex="-1">Issue 4: <code>1ai-hub</code> vs. <code>gbrain</code> <a class="header-anchor" href="#issue-4-1ai-hub-vs-gbrain" aria-label="Permalink to &quot;Issue 4: `1ai-hub` vs. `gbrain`&quot;">​</a></h3><ul><li><code>1ai-hub</code> contains a <code>brain/</code> module</li><li><code>~/projects/gbrain</code> also exists separately</li><li><strong>Risk:</strong> Split brain (pun intended) — two memory systems</li><li><strong>Recommendation:</strong> <code>1ai-hub/brain</code> is canonical; <code>gbrain</code> is the GB-era predecessor. Migrate any missing functionality, deprecate <code>gbrain</code>.</li></ul><hr><h2 id="_4-priority-repo-actions-by-workflow-impact" tabindex="-1">4. Priority Repo Actions (by workflow impact) <a class="header-anchor" href="#_4-priority-repo-actions-by-workflow-impact" aria-label="Permalink to &quot;4. Priority Repo Actions (by workflow impact)&quot;">​</a></h2><h3 id="tier-1-unlock-the-flywheel-do-first" tabindex="-1">Tier 1: Unlock the flywheel (do first) <a class="header-anchor" href="#tier-1-unlock-the-flywheel-do-first" aria-label="Permalink to &quot;Tier 1: Unlock the flywheel (do first)&quot;">​</a></h3><ol><li><strong>Build Capital Pool in <code>1ai-hub</code></strong> — unblocks everything downstream</li><li><strong>Deploy <code>1ai-social/marketplace</code> to production</strong> — WF6 starts generating income</li><li><strong>Connect <code>1ai-trade-cex</code> PnL → Capital Pool</strong> — WF5 loop closes</li></ol><h3 id="tier-2-strengthen-existing-workflows" tabindex="-1">Tier 2: Strengthen existing workflows <a class="header-anchor" href="#tier-2-strengthen-existing-workflows" aria-label="Permalink to &quot;Tier 2: Strengthen existing workflows&quot;">​</a></h3><ol start="4"><li><strong>Audit <code>1ai-trade-bot</code></strong> — clarify vs. <code>1ai-trade-cex</code>, kill/merge</li><li><strong>Build WF2 outreach module</strong> in <code>1ai-social</code> — longest-running gap</li><li><strong>Instrument <code>1ai-berkahkarya-website</code> payments</strong> → Capital Pool</li></ol><h3 id="tier-3-polish-and-optimize" tabindex="-1">Tier 3: Polish and optimize <a class="header-anchor" href="#tier-3-polish-and-optimize" aria-label="Permalink to &quot;Tier 3: Polish and optimize&quot;">​</a></h3><ol start="7"><li><strong>Consolidate skills</strong> — single canonical location</li><li><strong>Hermes trigger rules</strong> — load brainstorm C thresholds into Hermes</li><li><strong>Vilona Capital Pool awareness</strong> — feed pool snapshot to Vilona&#39;s context</li></ol><hr><h2 id="_5-the-5-files-that-matter-most-right-now" tabindex="-1">5. The 5 Files That Matter Most Right Now <a class="header-anchor" href="#_5-the-5-files-that-matter-most-right-now" aria-label="Permalink to &quot;5. The 5 Files That Matter Most Right Now&quot;">​</a></h2><p>Given all the repos, these 5 files are the most critical path:</p><ol><li><code>1ai-hub/src/capital_pool/service.py</code> — <strong>doesn&#39;t exist yet, needs to be built</strong></li><li><code>1ai-social/ai_social/marketplace/treasury.py</code> — <strong>exists, needs Capital Pool hookup</strong></li><li><code>1ai-trade-cex/trading_bot/server.py</code> — <strong>exists, needs PnL reporting to pool</strong></li><li><code>.hermes/hermes-agent/</code> — <strong>exists, needs trigger rules loaded</strong></li><li><code>1ai-hub/hub-core/src/hub_core/clients/capital_pool.py</code> — <strong>doesn&#39;t exist, needs to be built</strong></li></ol><hr><h2 id="_6-summary-diagram" tabindex="-1">6. Summary Diagram <a class="header-anchor" href="#_6-summary-diagram" aria-label="Permalink to &quot;6. Summary Diagram&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WF1: 1ai-content ──────────────────────────────┐</span></span>\n<span class="line"><span>WF2: (missing) ─────────────────────────────────┤</span></span>\n<span class="line"><span>WF3: 1ai-berkahkarya-website + 1ai-payment ─────┤──→ [CAPITAL POOL]  ──→  WF5: 1ai-trade-cex</span></span>\n<span class="line"><span>WF4: 1ai-trade-cex (subscriptions) ─────────────┤      (1ai-hub)          (multiply capital)</span></span>\n<span class="line"><span>WF6: 1ai-social/marketplace ─────────────────────┘</span></span>\n<span class="line"><span>                                                      ↑</span></span>\n<span class="line"><span>                                            .hermes/hermes-agent</span></span>\n<span class="line"><span>                                            (orchestration)</span></span>\n<span class="line"><span>                                                      ↑</span></span>\n<span class="line"><span>                                               Vilona persona</span></span>\n<span class="line"><span>                                            (strategic layer)</span></span></code></pre></div><p><strong>Current state:</strong> All arrows MISSING (Capital Pool doesn&#39;t exist).<br><strong>Target state:</strong> All arrows AUTOMATED (Hermes monitors and routes everything).</p>',77)])])}const g=e(r,[["render",i]]);export{u as __pageData,g as default};
